function debounce(fn, ms) {
  let t;
  return function(...args) {
    clearTimeout(t);
    t = setTimeout(() => fn.apply(this, args), ms);
  };
}

function once(fn) {
  let called = false, val;
  return function(...a) {
    if (called) return val;
    called = true;
    return val = fn.apply(this, a);
  };
}

async function* paginate(fetcher) {
  let cursor = null;
  do {
    const page = await fetcher(cursor);
    yield* page.items;
    cursor = page.nextCursor;
  } while (cursor);
}

